const body = $input.first().json;

const required = ['story_id', 'organization_id'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const process_id = body.process_id ?? `proc_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;

return [{
  json: {
    process_id,
    story_id: body.story_id,
    org_id: body.organization_id,
    organization_id: body.organization_id,
    triggered_by: body.user_id ?? 'system',
    governance: {
      max_rework_cycles: 3,
      arch_rework_count: 0,
      impl_rework_count: 0,
      deploy_rework_count: 0,
    },
    stages_completed: [],
    current_stage: 'intake',
    intake_at: new Date().toISOString(),
  }
}];

const response = $input.first().json;
const artifact = response.artifact ?? {};

// Schema check
if (!response.agent || !response.artifact_type) {
  throw new Error('Invalid ScrumMasterAI artifact: missing agent or artifact_type');
}
if (response.artifact_type !== 'story_analysis') {
  throw new Error(`Unexpected artifact_type: ${response.artifact_type}`);
}

const intake = $('Stage: Intake').first().json;
return [{
  json: {
    ...intake,
    current_stage: 'story_analysis',
    story_analysis: {
      dor_passed: artifact.dor_passed ?? false,
      missing_fields: artifact.missing_fields ?? [],
      tasks: artifact.tasks ?? [],
      dependencies: artifact.dependencies ?? [],
      required_agents: artifact.required_agents ?? [],
      risk_assessment: artifact.risk_assessment ?? 'medium',
    },
    scrum_master_blocking: response.blocking ?? !artifact.dor_passed,
    stages_completed: [...(intake.stages_completed ?? []), 'story_analysis'],
  }
}];

const input = $input.first().json;
const findings = input.story_analysis?.missing_fields ?? [];
return [{
  json: {
    status: 'blocked',
    reason: 'dor_not_met',
    story_id: input.story_id,
    org_id: input.org_id,
    findings,
    message: `Story does not meet Definition of Ready. Missing: ${findings.join(', ')}`,
    blocked_at: new Date().toISOString(),
  }
}];

const response = $input.first().json;
if (!response.artifact || response.artifact_type !== 'architecture_design') {
  throw new Error('Invalid ArchitectAI artifact');
}
const prev = $('Gate: Story Ready?').first().json;
return [{
  json: {
    ...prev,
    current_stage: 'architecture_design',
    architecture: response.artifact,
    arch_blocking: response.blocking ?? false,
    stages_completed: [...(prev.stages_completed ?? []), 'architecture_design'],
  }
}];

// Parallel invocations of 6 review agents
// In production use n8n's splitInBatches or HTTP parallel execution
// Here we prepare the review request payload
const input = $input.first().json;
const reviewAgents = ['security-ai', 'performance-ai', 'ux-ai', 'database-ai', 'network-ai', 'testing-ai'];

return reviewAgents.map(agentId => ({
  json: {
    ...input,
    review_agent_id: agentId,
    current_stage: 'architecture_review',
  }
}));

// Collect all review agent responses
const items = $input.all();
const reviews = items.map((item, i) => ({
  agent: item.json.agent ?? `review_agent_${i}`,
  status: item.json.status ?? 'OK',
  blocking: item.json.blocking ?? false,
  findings: item.json.findings ?? [],
  artifact: item.json.artifact ?? {},
}));

const prev = $('Validate Architecture').first().json;

return [{
  json: {
    ...prev,
    review_artifacts: reviews,
    current_stage: 'architecture_review_collected',
    stages_completed: [...(prev.stages_completed ?? []), 'architecture_review'],
  }
}];

const input = $input.first().json;
const reviews = input.review_artifacts ?? [];

const securityReview = reviews.find(r => r.agent?.toLowerCase().includes('security'));
const performanceReview = reviews.find(r => r.agent?.toLowerCase().includes('performance'));
const otherReviews = reviews.filter(r => r !== securityReview && r !== performanceReview);

let decision = 'approved';
let reason = 'All reviews passed';

if (securityReview?.blocking) {
  decision = 'blocked';
  reason = 'SecurityAI blocking — architecture must not proceed';
} else if (performanceReview?.blocking) {
  decision = 'rework_required';
  reason = 'PerformanceAI blocking — rework required';
} else if (otherReviews.some(r => r.blocking)) {
  decision = 'rework_required';
  const blocking = otherReviews.filter(r => r.blocking).map(r => r.agent);
  reason = `Blocking reviews from: ${blocking.join(', ')}`;
} else if (reviews.some(r => r.status === 'WARNING')) {
  decision = 'approved_with_actions';
  reason = 'Warnings present — approved with required actions';
}

const newArchReworkCount = input.governance.arch_rework_count ?? 0;

return [{
  json: {
    ...input,
    current_stage: 'architecture_consolidation',
    consolidation: {
      decision,
      reason,
      all_findings: reviews.flatMap(r => r.findings),
      review_summary: reviews.map(r => ({ agent: r.agent, status: r.status, blocking: r.blocking })),
    },
    governance: {
      ...input.governance,
      arch_rework_count: decision === 'rework_required' ? newArchReworkCount + 1 : newArchReworkCount,
    },
    stages_completed: [...(input.stages_completed ?? []), 'architecture_consolidation'],
  }
}];

const input = $input.first().json;
if (input.governance.arch_rework_count >= 3) {
  return [{ json: { ...input, status: 'manual_intervention_required', reason: 'Max architecture rework cycles exceeded (3)', blocked_at: new Date().toISOString() } }];
}
// Return to architecture design with incremented counter
// In production: loop via n8n's loop node or redirect
return [{ json: { ...input, _rework_loop: true, return_to: 'architecture_design' } }];

const response = $input.first().json;
if (!response.artifact || response.artifact_type !== 'implementation') {
  throw new Error('Invalid CodingAI artifact: expected implementation');
}
const prev = $('Gate: Architecture Approved?').first().json;
return [{
  json: {
    ...prev,
    current_stage: 'implementation',
    implementation: response.artifact,
    impl_blocking: response.blocking ?? false,
    stages_completed: [...(prev.stages_completed ?? []), 'implementation'],
  }
}];

const input = $input.first().json;
const reviewAgents = ['security-ai', 'performance-ai', 'testing-ai', 'database-ai', 'network-ai', 'ux-ai'];
return reviewAgents.map(agentId => ({
  json: { ...input, review_agent_id: agentId, current_stage: 'post_impl_review' }
}));

const input = $input.first().json;
const count = (input.governance.impl_rework_count ?? 0) + 1;
if (count >= 3) {
  return [{ json: { ...input, status: 'manual_intervention_required', reason: 'Max implementation rework cycles exceeded (3)', blocked_at: new Date().toISOString() } }];
}
return [{ json: { ...input, governance: { ...input.governance, impl_rework_count: count }, _rework_loop: true, return_to: 'implementation' } }];

const input = $input.first().json;
const deployAgents = ['deploy-ai', 'security-ai', 'network-ai'];
return deployAgents.map(agentId => ({
  json: { ...input, deploy_agent_id: agentId, current_stage: 'deployment_preparation' }
}));

const input = $input.first().json;
const docResponse = $('Stage: Documentation').first().json;

const docBlocking = docResponse.blocking ?? false;
const allGatesPassed = !input.deploy_blocking && !input.impl_blocking && !input.arch_blocking;

let release_decision = 'approved';
let release_reason = 'All stages passed successfully';

if (!allGatesPassed) {
  release_decision = 'rejected';
  release_reason = 'One or more gates failed';
} else if (docBlocking) {
  release_decision = 'conditional';
  release_reason = 'Documentation incomplete — conditional approval';
}

const semver = (() => {
  const d = new Date();
  return `${d.getFullYear()}.${d.getMonth()+1}.${d.getDate()}`;
})();

return [{
  json: {
    ...input,
    current_stage: 'final_release_decision',
    release_decision: {
      decision: release_decision,
      reason: release_reason,
      version: semver,
      decided_at: new Date().toISOString(),
      process_id: input.process_id,
      story_id: input.story_id,
      gates: {
        architecture: !input.arch_blocking,
        implementation: !input.impl_blocking,
        deployment: !input.deploy_blocking,
        documentation: !docBlocking,
      },
    },
    stages_completed: [...(input.stages_completed ?? []), 'final_release_decision'],
  }
}];

const input = $input.first().json;

// Emit completion event
console.log('Event: ai_delivery.completed', JSON.stringify({
  process_id: input.process_id,
  story_id: input.story_id,
  organization_id: input.org_id,
  release_decision: input.release_decision,
  stages_completed: input.stages_completed,
  completed_at: new Date().toISOString(),
}));

return [{
  json: {
    status: 'completed',
    process_id: input.process_id,
    story_id: input.story_id,
    release_decision: input.release_decision,
    stages_completed: input.stages_completed,
    governance: input.governance,
    completed_at: new Date().toISOString(),
  }
}];

const error = $input.first().json;
console.error('ai-delivery workflow error:', JSON.stringify({
  execution_id: $execution.id,
  error: error.message ?? error,
  timestamp: new Date().toISOString(),
}));
return [{
  json: {
    status: 'failed',
    error: error.message ?? String(error),
    execution_id: $execution.id,
    failed_at: new Date().toISOString(),
  }
}];
